import json, pandas as pd, re

def load_records(v):
    if isinstance(v, str) and v.endswith('.json'):
        with open(v, 'r', encoding='utf-8') as f:
            return json.load(f)
    return v

books = load_records(var_call_Qe2IwX2UoH8ew3EkKVFMDoTv)
bdf = pd.DataFrame(books)

pat_year = re.compile(r'\b((?:18|19|20)\d{2})\b')

def extract_year(s):
    if not isinstance(s, str):
        return None
    ms = pat_year.findall(s)
    if not ms:
        return None
    for ystr in ms:
        y = int(ystr)
        if 1800 <= y <= 2026:
            return y
    return None

bdf['year'] = bdf['details'].map(extract_year)
non_null = bdf['year'].dropna()

out = {
  'non_null_years': int(non_null.shape[0]),
  'unique_years_sample': sorted(non_null.unique().tolist())[:20] if non_null.shape[0]>0 else [],
  'details_null_count': int(bdf['details'].isna().sum()),
}

print('__RESULT__:')
print(json.dumps(out))

